#!/bin/bash

# =============================================================================
# TestToken ERC20 Deployment Script
# =============================================================================
# Deploys a TestToken ERC20 contract (name: "TestToken", symbol: "TT",
# 18 decimals, with public mint/burn) on a single chain using raw bytecode.
# Mints INITIAL_MINT tokens to the deployer after deployment.
#
# Reuse this script for both L1 and L2 by pointing FORK_URL at the desired RPC.
#
# Required environment variables:
#   PRIVATE_KEY    - Deployer private key
#   FORK_URL       - RPC URL of the target chain (L1 or L2)
#
# Optional environment variables:
#   INITIAL_MINT   - Amount to mint in wei (default: 1_000_000 TT = 10^24 wei)
#   CHAIN_LABEL    - Human-readable label for log output (default: "chain")
#   DEPLOYMENT_DIR - Directory to write result JSON (default: /deployment)
#   RESULT_FILE    - Override the output JSON filename entirely
# =============================================================================

set -e

DEPLOYMENT_DIR="${DEPLOYMENT_DIR:-/deployment}"
CHAIN_LABEL="${CHAIN_LABEL:-chain}"
# 1_000_000 TT with 18 decimals
INITIAL_MINT="${INITIAL_MINT:-1000000000000000000000000}"

# Output file: caller can override via RESULT_FILE, otherwise defaults to
# $DEPLOYMENT_DIR/test-token-<CHAIN_LABEL>.json
RESULT_FILE="${RESULT_FILE:-$DEPLOYMENT_DIR/test-token-${CHAIN_LABEL}.json}"

# TestToken bytecode — compiled from TestToken.sol with OZ v4.9.6 ERC20
# Solidity 0.8.30 — standard approve/transferFrom/mint/burn, 18 decimals
TEST_TOKEN_BYTECODE=""

echo "============================================="
echo " TestToken ERC20 Deployment"
echo "============================================="
echo ""

SENDER=$(cast wallet address --private-key "$PRIVATE_KEY")
CHAIN_ID=$(cast chain-id --rpc-url "$FORK_URL")

echo "  Chain label:   $CHAIN_LABEL"
echo "  Chain ID:      $CHAIN_ID"
echo "  RPC URL:       $FORK_URL"
echo "  Deployer:      $SENDER"
echo "  Initial mint:  $INITIAL_MINT wei"
echo "  Result file:   $RESULT_FILE"
echo ""

# ---------------------------------------------------------------
# Step 1: Deploy TestToken
# ---------------------------------------------------------------

echo "============================================="
echo " Step 1/2: Deploying TestToken"
echo "============================================="
echo ""

receipt=$(cast send \
    --rpc-url "$FORK_URL" \
    --private-key "$PRIVATE_KEY" \
    --create "$TEST_TOKEN_BYTECODE" \
    --json)

TOKEN_ADDR=$(echo "$receipt" | jq -r '.contractAddress')

if [[ -z "$TOKEN_ADDR" || "$TOKEN_ADDR" == "null" ]]; then
    echo "ERROR: could not extract contract address from deploy receipt"
    echo "$receipt"
    exit 1
fi

echo "  TestToken deployed at: $TOKEN_ADDR"
echo ""

# ---------------------------------------------------------------
# Step 2: Mint initial supply to deployer
# ---------------------------------------------------------------

echo "============================================="
echo " Step 2/2: Minting initial supply to deployer"
echo "============================================="
echo ""

cast send \
    --rpc-url "$FORK_URL" \
    --private-key "$PRIVATE_KEY" \
    "$TOKEN_ADDR" \
    "mint(uint256)" "$INITIAL_MINT" \
    --json > /dev/null

BALANCE=$(cast call --rpc-url "$FORK_URL" "$TOKEN_ADDR" "balanceOf(address)(uint256)" "$SENDER")
echo "  Deployer balance: $BALANCE wei"
echo ""

# ---------------------------------------------------------------
# Save result
# ---------------------------------------------------------------

cat > "$RESULT_FILE" <<EOF
{
  "test_token": "$TOKEN_ADDR",
  "chain_id": "$CHAIN_ID",
  "chain_label": "$CHAIN_LABEL",
  "deployer": "$SENDER",
  "initial_mint_wei": "$INITIAL_MINT"
}
EOF

echo "============================================="
echo " TestToken Deployment Complete"
echo "============================================="
echo ""
echo "  Chain:       $CHAIN_LABEL (chain ID $CHAIN_ID)"
echo "  TestToken:   $TOKEN_ADDR"
echo "  Deployer:    $SENDER"
echo "  Balance:     $BALANCE wei"
echo ""
echo "  Result saved to: $RESULT_FILE"
echo "============================================="
